import{bQ as e,aL as a,u as s,G as d}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"K8s 基础概念","description":"","frontmatter":{},"headers":[],"relativePath":"10.Kubernetes/01-K8s基础概念.md","filePath":"10.Kubernetes/01-K8s基础概念.md","lastUpdated":null}'),i={name:"10.Kubernetes/01-K8s基础概念.md"};function r(l,t,n,p,h,E){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="k8s-基础概念" tabindex="-1">K8s 基础概念 <a class="header-anchor" href="#k8s-基础概念" aria-label="Permalink to &quot;K8s 基础概念&quot;">​</a></h1><p>Docker 解决单个容器怎么运行。Compose 解决单机多容器怎么组织。当服务要跑在多台机器上、副本数要动态调整、某台机器挂了服务要自动迁走时，这两样就不够了。</p><p>Kubernetes 处理的是多节点、多副本、多服务长期运行时的调度、网络、存储、配置、发布和故障恢复。</p><h2 id="编排的本质——声明期望状态" tabindex="-1">编排的本质——声明期望状态 <a class="header-anchor" href="#编排的本质——声明期望状态" aria-label="Permalink to &quot;编排的本质——声明期望状态&quot;">​</a></h2><p>Kubernetes 的工作方式是：提交期望状态（&quot;我要 3 个 web 副本&quot;），控制器持续把集群实际状态调整到期望状态。副本少了就补，多了就缩，节点坏了就在别处重建。</p><p>不用 K8s 时，这些动作通常是运维脚本在做——检查进程、手动重启、改 Nginx upstream、更新 DNS。用 K8s 之后，这些&quot;检查→纠正&quot;的循环由控制器接管。</p><p>K8s 覆盖的主要场景和对应核心对象如下。Pod、Service、ConfigMap 这些对象先按职责区分，具体字段和排查方式会落到对应资源里。</p><table tabindex="0"><thead><tr><th>场景</th><th>Kubernetes 负责的部分</th></tr></thead><tbody><tr><td>多副本 Web/API</td><td>调度 Pod（最小调度单元，一组容器）、维护副本数、滚动发布</td></tr><tr><td>服务发现</td><td>Service 提供稳定访问入口，Pod IP 变化不影响调用方</td></tr><tr><td>节点故障</td><td>节点异常后，控制器在其他节点重建副本</td></tr><tr><td>配置分发</td><td>ConfigMap（明文配置）、Secret（敏感配置）挂载或注入到容器</td></tr><tr><td>资源约束</td><td>requests（申请量）、limits（上限）、QoS、驱逐策略</td></tr><tr><td>发布治理</td><td>滚动更新、回滚、蓝绿、金丝雀</td></tr><tr><td>可观测性</td><td>事件、日志、指标、审计</td></tr></tbody></table><p>K8s 把调度、服务发现、配置挂载、滚动更新这些动作标准化了。但应用自身的启动逻辑、健康检查、数据一致性、数据库迁移、连接池配置仍然是应用和运维一起处理的——平台提供能力，不替代应用设计。</p><h2 id="集群结构——控制平面和工作节点" tabindex="-1">集群结构——控制平面和工作节点 <a class="header-anchor" href="#集群结构——控制平面和工作节点" aria-label="Permalink to &quot;集群结构——控制平面和工作节点&quot;">​</a></h2><p>一个集群分成两部分：控制平面负责决策和记录状态，工作节点负责运行容器。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20TB%0A%20%20%20%20user%5B%22%E8%BF%90%E7%BB%B4%E7%BB%88%E7%AB%AF%3Cbr%2F%3Ekubectl%20%2F%20GitOps%20%2F%20%E6%8E%A7%E5%88%B6%E5%8F%B0%22%5D%20--%3E%20api%5B%22kube-apiserver%3Cbr%2F%3E%E9%9B%86%E7%BE%A4%20API%20%E5%85%A5%E5%8F%A3%22%5D%0A%0A%20%20%20%20subgraph%20cp%5B%22%E6%8E%A7%E5%88%B6%E5%B9%B3%E9%9D%A2%22%5D%0A%20%20%20%20%20%20%20%20api%20--%3E%20etcd%5B%22etcd%3Cbr%2F%3E%E4%BF%9D%E5%AD%98%E9%9B%86%E7%BE%A4%E7%8A%B6%E6%80%81%22%5D%0A%20%20%20%20%20%20%20%20scheduler%5B%22kube-scheduler%3Cbr%2F%3E%E4%B8%BA%20Pod%20%E9%80%89%E6%8B%A9%E8%8A%82%E7%82%B9%22%5D%20--%3E%20api%0A%20%20%20%20%20%20%20%20controller%5B%22kube-controller-manager%3Cbr%2F%3E%E8%BF%90%E8%A1%8C%E6%8E%A7%E5%88%B6%E5%99%A8%22%5D%20--%3E%20api%0A%20%20%20%20end%0A%0A%20%20%20%20api%20--%3E%20node01%5B%22%E5%B7%A5%E4%BD%9C%E8%8A%82%E7%82%B9%2001%3Cbr%2F%3Ekubelet%20%2F%20containerd%20%2F%20kube-proxy%22%5D%0A%20%20%20%20api%20--%3E%20node02%5B%22%E5%B7%A5%E4%BD%9C%E8%8A%82%E7%82%B9%2002%3Cbr%2F%3Ekubelet%20%2F%20containerd%20%2F%20kube-proxy%22%5D%0A"></div><p>所有组件都通过 <code>kube-apiserver</code> 读写资源对象——kubectl、scheduler、controller-manager、kubelet 没有例外。etcd 只在 API Server 后面做持久化存储，没有组件直接操作 etcd。这意味着：想查集群里有什么对象、想改对象的状态、想监听变化——全部走 API Server。这个设计让认证、授权、审计和准入控制在同一个入口完成，不需要在每个组件上分别做一遍。</p><h2 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to &quot;核心组件&quot;">​</a></h2><p>每个组件解决一类问题：</p><table tabindex="0"><thead><tr><th>组件</th><th>所在位置</th><th>解决的问题</th><th>常见故障</th></tr></thead><tbody><tr><td><code>kube-apiserver</code></td><td>控制平面</td><td>提供统一的 API 入口</td><td>证书过期、认证失败、请求延迟高</td></tr><tr><td><code>etcd</code></td><td>控制平面</td><td>持久化保存所有集群对象状态</td><td>磁盘慢、快照丢失、quorum 丢失</td></tr><tr><td><code>kube-scheduler</code></td><td>控制平面</td><td>新 Pod 应该放在哪个节点</td><td>资源不足、污点、亲和性、PVC 未绑定</td></tr><tr><td><code>kube-controller-manager</code></td><td>控制平面</td><td>持续调和期望状态和实际状态</td><td>副本不补、节点状态更新异常</td></tr><tr><td><code>kubelet</code></td><td>每个节点</td><td>管理本节点的 Pod 和容器生命周期</td><td>镜像拉取失败、挂载失败、探针失败</td></tr><tr><td><code>containerd / CRI-O</code></td><td>每个节点</td><td>容器运行时——真正创建和运行容器</td><td>镜像损坏、容器创建失败</td></tr><tr><td><code>kube-proxy</code></td><td>每个节点</td><td>把 Service 规则变成节点上的转发规则</td><td>iptables/IPVS 规则异常、Service 不通</td></tr><tr><td>CNI 插件</td><td>每个节点</td><td>给 Pod 分配 IP、实现 Pod 间通信</td><td>Pod 无 IP、跨节点不通、策略异常</td></tr></tbody></table><p>etcd 是整个集群状态的唯一持久化存储。控制平面节点故障后可以重建，Pod 可以重建——etcd 数据丢了等于集群所有对象（Deployment、Service、ConfigMap、Secret、RBAC）全部丢失。生产集群里 etcd 快照、证书有效期、磁盘延迟是固定巡检项。</p><h2 id="声明式-api-和控制循环" tabindex="-1">声明式 API 和控制循环 <a class="header-anchor" href="#声明式-api-和控制循环" aria-label="Permalink to &quot;声明式 API 和控制循环&quot;">​</a></h2><p>K8s 的基本动作不是&quot;执行一次命令&quot;，而是&quot;提交期望状态，控制器持续调和&quot;：</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20%20%20participant%20ops%20as%20%E8%BF%90%E7%BB%B4%E7%BB%88%E7%AB%AF%0A%20%20%20%20participant%20api%20as%20kube-apiserver%0A%20%20%20%20participant%20etcd%20as%20etcd%0A%20%20%20%20participant%20ctl%20as%20%E6%8E%A7%E5%88%B6%E5%99%A8%0A%20%20%20%20participant%20sch%20as%20%E8%B0%83%E5%BA%A6%E5%99%A8%0A%20%20%20%20participant%20kubelet%20as%20%E8%8A%82%E7%82%B9%20kubelet%0A%20%20%20%20participant%20runtime%20as%20%E5%AE%B9%E5%99%A8%E8%BF%90%E8%A1%8C%E6%97%B6%0A%0A%20%20%20%20ops-%3E%3Eapi%3A%20apply%20Deployment%0A%20%20%20%20api-%3E%3Eetcd%3A%20%E4%BF%9D%E5%AD%98%E6%9C%9F%E6%9C%9B%E7%8A%B6%E6%80%81%0A%20%20%20%20ctl-%3E%3Eapi%3A%20%E5%88%9B%E5%BB%BA%20ReplicaSet%20%2F%20Pod%0A%20%20%20%20sch-%3E%3Eapi%3A%20%E7%BB%99%20Pending%20Pod%20%E7%BB%91%E5%AE%9A%E8%8A%82%E7%82%B9%0A%20%20%20%20kubelet-%3E%3Eapi%3A%20%E7%9B%91%E5%90%AC%E6%9C%AC%E8%8A%82%E7%82%B9%20Pod%0A%20%20%20%20kubelet-%3E%3Eruntime%3A%20%E6%8B%89%E9%95%9C%E5%83%8F%E5%B9%B6%E5%88%9B%E5%BB%BA%E5%AE%B9%E5%99%A8%0A%20%20%20%20kubelet--%3E%3Eapi%3A%20%E4%B8%8A%E6%8A%A5%20Pod%20%E7%8A%B6%E6%80%81%0A"></div><p>把 Deployment 副本数从 2 改到 5 时，实际发生的不是&quot;启动三个新容器&quot;一条指令，而是每个组件接力完成自己那一段。变更后的状态传递过程：</p><table tabindex="0"><thead><tr><th>步骤</th><th>哪个组件</th><th>具体动作</th></tr></thead><tbody><tr><td>修改 <code>spec.replicas</code> 为 5</td><td>API Server</td><td>接收新期望状态，写入 etcd</td></tr><tr><td>Deployment 控制器发现差异</td><td>controller-manager</td><td>当前 2 个副本 &lt; 期望 5 个副本</td></tr><tr><td>创建 3 个新 Pod</td><td>controller-manager</td><td>新 Pod 字段写入 etcd</td></tr><tr><td>给 Pod 选节点</td><td>scheduler</td><td>写入 Pod 的 <code>spec.nodeName</code></td></tr><tr><td>拉起容器</td><td>kubelet</td><td>节点上拉镜像、挂载卷、启动进程</td></tr></tbody></table><p>这个接力模型直接决定了排错方式。API 是否接收对象、控制器是否创建对象、调度是否成功、kubelet 是否创建容器、应用是否健康——五个不同阶段，排查入口和日志来源完全不同。</p><h2 id="spec-和-status" tabindex="-1">spec 和 status <a class="header-anchor" href="#spec-和-status" aria-label="Permalink to &quot;spec 和 status&quot;">​</a></h2><p>Kubernetes 不直接操作进程，而是操作资源对象。所有资源对象共享一个结构：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">apps/v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Deployment</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">web</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  namespace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">demo</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  labels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">web</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  replicas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  selector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    matchLabels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">web</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  template</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      labels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">web</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      containers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx:1.26</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 由控制器维护，用户不写</span></span></code></pre></div><p><code>spec</code> 是期望状态——用户写的内容。<code>status</code> 是当前状态——控制器写的内容。Pod IP、Ready 状态、重启次数、Deployment 可用副本数都在 status 里。</p><p>注意 YAML 里 <code>selector.matchLabels</code> 和 <code>template.metadata.labels</code> 写了同样的 <code>app: web</code>——这不是重复。selector 告诉 Deployment&quot;哪些 Pod 归我管&quot;，template labels 是 Pod 出生时被打上的标记。两边的值必须匹配，否则 Deployment 创建出来的 Pod 不会被它自己识别，会导致副本数失控。</p><p>常见资源对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>解决的问题</th></tr></thead><tbody><tr><td>Namespace</td><td>资源按项目/环境分组，权限作用范围</td></tr><tr><td>Pod</td><td>最小调度单元——一组共享网络和存储的容器</td></tr><tr><td>Deployment</td><td>管理无状态副本，滚动更新和回滚</td></tr><tr><td>StatefulSet</td><td>管理有状态副本，提供稳定网络身份和持久存储</td></tr><tr><td>DaemonSet</td><td>每个节点跑一个 Pod（日志采集、监控 Agent、CNI）</td></tr><tr><td>Service</td><td>提供不随 Pod IP 变化的稳定访问入口</td></tr><tr><td>ConfigMap</td><td>注入非敏感的明文配置</td></tr><tr><td>Secret</td><td>注入敏感配置（密码、Token、证书）</td></tr><tr><td>Ingress / Gateway</td><td>七层入口规则（域名路由、TLS、灰度）</td></tr><tr><td>PV / PVC / StorageClass</td><td>把存储从 Pod 生命周期里独立出来</td></tr></tbody></table><h2 id="label-和-selector——资源关联的核心" tabindex="-1">label 和 selector——资源关联的核心 <a class="header-anchor" href="#label-和-selector——资源关联的核心" aria-label="Permalink to &quot;label 和 selector——资源关联的核心&quot;">​</a></h2><p>K8s 里资源之间不靠固定 IP，靠 label 和 selector 建立关联：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20deploy%5B%22Deployment%3Cbr%2F%3Eselector%3A%20app%3Dweb%22%5D%20--%3E%20pod1%5B%22Pod%2001%3Cbr%2F%3Elabel%3A%20app%3Dweb%22%5D%0A%20%20%20%20deploy%20--%3E%20pod2%5B%22Pod%2002%3Cbr%2F%3Elabel%3A%20app%3Dweb%22%5D%0A%20%20%20%20svc%5B%22Service%3Cbr%2F%3Eselector%3A%20app%3Dweb%22%5D%20--%3E%20pod1%0A%20%20%20%20svc%20--%3E%20pod2%0A%20%20%20%20monitor%5B%22ServiceMonitor%3Cbr%2F%3Eselector%20%E5%8C%B9%E9%85%8D%20Service%20%E6%A0%87%E7%AD%BE%22%5D%20--%3E%20svc%0A"></div><table tabindex="0"><thead><tr><th>关系</th><th>关联方式</th></tr></thead><tbody><tr><td>Deployment → Pod</td><td><code>spec.selector.matchLabels</code> 匹配 Pod labels</td></tr><tr><td>Service → Pod</td><td><code>spec.selector</code> 匹配 Pod labels</td></tr><tr><td>NetworkPolicy → Pod</td><td><code>podSelector</code> 匹配 Pod labels</td></tr><tr><td>ServiceMonitor → Service</td><td>selector 匹配 Service labels</td></tr><tr><td>Pod → PVC</td><td><code>claimName</code> 引用 PVC 名称</td></tr><tr><td>Ingress/Gateway → Service</td><td>backend 引用 Service 名称和端口</td></tr></tbody></table><p>标签写错或没对上时不会报错——Service 安安静静地没有后端 Pod，Deployment 接管不到新 Pod，监控采集不到目标。排查 Service &quot;怎么不通&quot;时，先确认 selector 和 Pod labels 是否一致。</p><h2 id="k8s-的边界——什么能处理-什么处理不了" tabindex="-1">K8s 的边界——什么能处理，什么处理不了 <a class="header-anchor" href="#k8s-的边界——什么能处理-什么处理不了" aria-label="Permalink to &quot;K8s 的边界——什么能处理，什么处理不了&quot;">​</a></h2><table tabindex="0"><thead><tr><th>K8s 能处理</th><th>说明</th></tr></thead><tbody><tr><td>副本数维护</td><td>Pod 少了补，多了缩</td></tr><tr><td>调度</td><td>按资源、污点、亲和性选择节点</td></tr><tr><td>服务发现</td><td>Service 和 DNS 提供稳定访问入口</td></tr><tr><td>配置挂载</td><td>ConfigMap、Secret 注入容器</td></tr><tr><td>滚动发布</td><td>分批替换 Pod</td></tr><tr><td>基础自愈</td><td>容器退出后重启，节点故障后重调度</td></tr></tbody></table><table tabindex="0"><thead><tr><th>K8s 处理不了</th><th>现场表现</th></tr></thead><tbody><tr><td>应用启动逻辑错误</td><td>CrashLoopBackOff——容器反复退出重启</td></tr><tr><td>数据库一致性</td><td>Pod 重启不等于数据恢复——StatefulSet 提供稳定身份，不提供高可用方案</td></tr><tr><td>镜像 tag 混乱</td><td>同名 tag 在不同节点可能指向不同镜像内容</td></tr><tr><td>连接池过大</td><td>扩副本后数据库连接数打满——HPA 不会帮你调连接池</td></tr><tr><td>外部依赖故障</td><td>Pod Running，但接口超时——探针定义在 K8s 里，根因在外部</td></tr><tr><td>存储后端故障</td><td>PVC Bound，但挂载或 IO 异常——K8s 只看绑定状态，不看磁盘 IO</td></tr></tbody></table><p>Kubernetes 适合无状态服务、批处理任务、节点级采集组件和可水平扩展的应用。有状态服务也能跑，但存储、备份、升级顺序和故障切换需要单独设计。</p>`,39)])])}const k=e(i,[["render",r]]);export{c as __pageData,k as default};
